    'Preparation program for group running with tempo runs, drills, and lower body strength',
    'Social/Community Fitness'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Run Club Ready'
  AND pv.duration_weeks = 8
  AND pv.sessions_per_week = 4
ON CONFLICT DO NOTHING;

